// Time:  O(n + klogk), k is the distinct number of changed
// Space: O(k)

class Solution {
public:
    vector<int> findOriginalArray(vector<int>& changed) {
        if (size(changed) % 2) {
            return {};
        }
        unordered_map<int, int> cnts;
        for (const auto& x : changed) {
            ++cnts[x];
        }
        vector<int> nums;
        for (const auto& [x, _] : cnts) {
            nums.emplace_back(x);
        }
        sort(begin(nums), end(nums));
        vector<int> result;
        for (const auto& x : nums) {
            if (cnts[x] > cnts[2 * x]) {
                return {};
            }
            for (int i = 0; i < cnts[x]; ++i, --cnts[2 * x]) {
                result.emplace_back(x);
            }
        }
        return result;
    }
};

# Time:  O(n + klogk), k is the distinct number of changed
# Space: O(k)

class Solution(object):
    def findOriginalArray(self, changed):
        """
        :type changed: List[int]
        :rtype: List[int]
        """
        if len(changed)%2:
            return []
        cnts = collections.Counter(changed)
        for x in sorted(cnts.iterkeys()):
            if cnts[x] > cnts[2*x]:
                return []
            cnts[2*x] -= cnts[x] if x else cnts[x]//2
        return list(cnts.elements())
